// 读取当前文档全部文本内容
var doc = Application.ActiveDocument;
var content = '';
var paragraphs = doc.Paragraphs;
for (var i = 0; i < paragraphs.Count; i++) {
    content += paragraphs.Item(i).Range.Text;
}
return { content: content, length: content.length };

// 读取当前文档全部文本内容（修正遍历方式）
var doc = Application.ActiveDocument;
var content = '';
var paragraphs = doc.Paragraphs;
if (paragraphs && paragraphs.Count > 0) {
    for (var i = 1; i <= paragraphs.Count; i++) {
        var para = paragraphs.Item(i);
        if (para && para.Range) {
            content += para.Range.Text;
        }
    }
}
return { content: content, length: content.length };
